import{_ as e,o as n,c as i,e as s}from"./app-25fa875f.js";const a={},c=s(`<h1 id="compiler-multi-version-gcc" tabindex="-1"><a class="header-anchor" href="#compiler-multi-version-gcc" aria-hidden="true">#</a> Compiler - Multi-version GCC</h1><p>Created by : Mr Dk.</p><p>2020 / 05 / 07 22:50</p><p>Nanjing, Jiangsu, China</p><hr><p>在不同版本的 Linux distribution 中，有着不同默认版本的 GCC。比如 Ubuntu 18.04 自带 GCC 7.5.0，Ubuntu 20.04 自带 GCC 9.3.0。但是，有时编译一些以前的代码，会因为高版本编译器的严格要求而无法通过，使得我们不得不同时安装低版本的编译器。</p><p>通过源码编译安装好麻烦。最方便的方法当然是通过 APT 来安装历史版本的 GCC。但是如何管理多个版本的 GCC 是个麻烦事。使用 <code>build-essential</code> 可以进行方便地管理：</p><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ sudo update-alternatives --install /usr/bin/gcc gcc /usr/bin/gcc-9 9
$ sudo update-alternatives --install /usr/bin/gcc gcc /usr/bin/gcc-8 8
$ sudo update-alternatives --install /usr/bin/gcc gcc /usr/bin/gcc-7 7
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后通过如下命令可以替换 <code>gcc</code> 默认指向的 GCC 版本：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> update-alternatives <span class="token parameter variable">--config</span> gcc
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,10),l=[c];function r(t,d){return n(),i("div",null,l)}const u=e(a,[["render",r],["__file","Compiler Multi-version GCC.html.vue"]]);export{u as default};
